import React from 'react'
import Svg, { Circle, Line, Mask, Path, Rect, type SvgProps } from 'react-native-svg'
import { useCSSVariable } from 'uniwind'

/**
 * Social Icons Component Library (React Native — react-native-svg)
 *
 * @example
 * // Basic usage
 * import { DiscordIcon, TelegramIcon, XIcon } from '@/icons/socials'
 *
 * <DiscordIcon />
 * <TelegramIcon />
 * <XIcon />
 *
 * @example
 * // With custom size
 * <DiscordIcon size={32} />
 * <TelegramIcon size={16} />
 *
 * @example
 * // With className for styling (Uniwind)
 * <DiscordIcon className="text-blue-500" />
 * <TelegramIcon className="text-blue-400" size={24} />
 */

export interface IconProps extends SvgProps {
  size?: number | string
  className?: string
}

const createIconComponent = (name: string, children: React.ReactNode) => {
  const IconComponent = React.forwardRef<React.ComponentRef<typeof Svg>, IconProps>(
    ({ size = 24, className, color, ...props }, ref) => {
      const themeColor = useCSSVariable('--color-content-primary') as string | undefined
      const resolvedColor = color ?? (className ? undefined : themeColor)

      return (
        <Svg
          ref={ref}
          width={size}
          height={size}
          viewBox="0 0 24 24"
          fill="none"
          color={resolvedColor}
          className={className}
          {...props}
        >
          {children}
        </Svg>
      )
    },
  )
  IconComponent.displayName = name
  return IconComponent
}

